#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int maxn = 30010;

int n, m, tot, ans;
int lst = 1, lnk[maxn];
struct Edge {
    int to, nxt;
} e[maxn << 1];
struct Node {
    int dep, siz, fa, hson, top;
} a[maxn];

void addEdge(int x, int y) {
    e[++tot] = {y, lnk[x]};
    lnk[x] = tot;
}

void dfs1(int u, int fa, int depth) {
    a[u].dep = depth;
    a[u].siz = 1;
    a[u].fa = fa;
    a[u].hson = 0;
    for (int i = lnk[u]; i; i = e[i].nxt) {
        int v = e[i].to;
        if (v == fa) continue;
        dfs1(v, u, depth + 1);
        a[u].siz += a[v].siz;
        if (a[v].siz > a[a[u].hson].siz)
            a[u].hson = v;
    }
}

void dfs2(int u, int top) {
    a[u].top = top;
    if (a[u].hson) {
        dfs2(a[u].hson, top);
        for (int i = lnk[u]; i; i = e[i].nxt) {
            int v = e[i].to;
            if (v == a[u].fa || v == a[u].hson) continue;
            dfs2(v, v);
        }
    }
}

int LCA(int u, int v) {
    while (a[u].top != a[v].top) {
        if (a[a[u].top].dep < a[a[v].top].dep)
            swap(u, v);
        u = a[a[u].top].fa;
    }
    return a[u].dep < a[v].dep ? u : v;
}

int getDis(int u, int v) {
    int l = LCA(u, v);
    return a[u].dep + a[v].dep - 2 * a[l].dep;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cin >> n;
    for (int i = 1; i < n; ++i) {
        int u, v;
        cin >> u >> v;
        addEdge(u, v);
        addEdge(v, u);
    }
    dfs1(1, 0, 0);
    dfs2(1, 1);
    cin >> m;
    while (m--) {
        int x;
        cin >> x;
        ans += getDis(lst, x);
        lst = x;
    }
    cout << ans << endl;
    return 0;
}
